/* =========================================
   BASE
   ========================================= */
.card {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  font-size: 18px;
  text-align: center;
  color: #2E1A0A;
  background: #F5EFE0;
  line-height: 1.6;
  padding: 0 25px;
  max-width: 900px;
  margin: 20px auto;
}

.card::-webkit-scrollbar { display: none; }

.mobile .card {
  font-size: 16px;
  padding: 0;
  max-width: 100%;
  margin: 0;
}

/* =========================================
   NIGHT MODE BASE
   ========================================= */
.card.nightMode {
  background-color: #18160F;
  color: #C8BEA0;
  font-family: Arial, Helvetica, sans-serif;
}

/* =========================================
   TITLE
   ========================================= */
.title {
  font-size: 12px;
  color: #9E8A6A;
  letter-spacing: 0.06em;
  margin-bottom: 10px;
}

.nightMode .title { color: #5A5040; }

/* =========================================
   IMAGE (thẻ có ảnh thật)
   ========================================= */
.imgbox img,
img {
  max-width: 100%;
  height: 200px;
  width: 200px;
  border-radius: 12px;
	border: solid 1px #c49b63;
  object-fit: cover;
  margin-top: 5px;
  margin-bottom: 5px;
	box-shadow:0 0 6px gray;
  display: inline-block;
}

.nightMode .imgbox img,
.nightMode img {
  border-color: #2E2A1E;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.4);
}

/* =========================================
   IMAGE PLACEHOLDER (thẻ type — giữ layout)
   Cùng kích thước với ảnh thật để layout không nhảy
   ========================================= */
.imgbox-placeholder {
  display: inline-block;
  height: 200px;
  width: 200px;
  border-radius: 12px;
  border: 0.5px solid #C4B898;
	opacity:0.5;
  background: #EDE3CC;
  margin-top: 5px;
  margin-bottom: 5px;
  vertical-align: middle;
}

.nightMode .imgbox-placeholder {
  border-color: #2E2A1E;
  background: #211E14;
}

/* =========================================
   WORD
   ========================================= */
.word {
  font-family: Arial, Helvetica, sans-serif;
  font-weight: bold;
  font-size: 25px;
  color: #6B2600;
  margin-bottom: 3px;
}

.nightMode .word { color: #ff557f; }

/* =========================================
   HINT WORD (type card front)
   ========================================= */
.hint_word {
  font-family: Arial, sans-serif;
  font-size: 25px;
  color: #6B2600;
  text-align: center;
  margin-bottom: 6px;
}

.nightMode .hint_word { color: #ff557f; }
.mobile .hint_word    { color: #ff557f; margin-top: 3px; }

/* =========================================
   INPUT BOX
   ========================================= */
.prettify-box { margin: 6px 0; }

input[type=text] {
  min-width: 300px;
  height: 48px;
  text-align: center;
  padding: 5px 0;
  box-sizing: border-box;
  border-radius: 10px;
  border: 0.5px solid #C4B898;
  font-size: 22px;
  outline: none;
  background-color: #EDE3CC;
  color: #2E1A0A;
  margin: 8px 0;
}

.nightMode input[type=text] {
  color: #C8BEA0;
  background: #211E14;
  border-color: #2E2A1E;
  box-shadow: inset -2px -2px 2px #1E1C14, inset 2px 2px 2px #0E0C08;
}

/* =========================================
   TRANSCRIPTION
   ========================================= */
.transcription {
  font-family: "Lucida Sans Unicode", "Lucida Grande", sans-serif;
  font-size: 16px;
  color: #4A3A7A;
  margin-bottom: 3px;
}

.nightMode .transcription { color: #9090C8; }

/* =========================================
   PART OF SPEECH
   ========================================= */
.part-of-speech {
  font-size: 13px;
  color: #9E8A6A;
  margin-bottom: 6px;
}

.nightMode .part-of-speech { color: #5A5040; }

/* =========================================
   SEPARATOR
   ========================================= */
.sep {
  height: 0.5px;
  background: #C9BAA0;
  width: 55%;
  margin: 10px auto;
  opacity: 0.6;
}

.nightMode .sep {
  background: #2E2A1E;
  opacity: 1;
}

/* =========================================
   MEANINGS
   ========================================= */
.meaning-ja {
  font-family: UD Digi Kyokasho N-R, 'Source Sans Pro', "Segoe UI", Arial, sans-serif;
  font-weight: 600;
  font-size: 20px;
  color: #1A3A5A;
  margin: 4px 0;
}

.nightMode .meaning-ja {
  color: #c49b63;
  font-weight: normal;
}

.meaning-vn {
  font-family: arial !important, Georgia, "Times New Roman", serif;
  font-size: 17px;
  font-style: italic;
  color: #3A1A5A;
  margin: 4px 0 12px;
}

.nightMode .meaning-vn { color: #C8BEA0; }

/* =========================================
   EXAMPLE BLOCK
   ========================================= */
.tabs { margin: 4px 0; }

.tab-content {
  border-radius: 0 5px 5px 5px;
  box-shadow: 0 2px 8px rgba(80, 60, 20, 0.05);
}

.nightMode .tab-content { box-shadow: none; }

.example-item {
  border-left: 2.5px solid #C4A882;
  border-radius: 0 6px 6px 0;
  padding: 9px 10px 9px 34px;
  position: relative;
  margin-bottom: 10px;
  background: #EDE3CC;
  transition: all 0.3s ease;
}

.nightMode .example-item {
  border-left-color: #5A4A30;
  background: #211E14;
}

.example-number {
  position: absolute;
  left: 7px;
  top: 10px;
  width: 20px;
  height: 20px;
  background: #9E6A40;
  color: #F5EFE0;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: bold;
  font-size: 11px;
  transition: all 0.3s ease;
}

.nightMode .example-number {
  background: #6A5030;
  color: #C8BEA0;
}

.example-item:hover .example-number { transform: scale(1.1); }

.example-content {
  text-align: left;
  padding-left: 8px;
  line-height: 1.5;
}

.example {
  font-size: 16px;
  color: #2E1A0A;
  margin-bottom: 3px;
}

.nightMode .example { color: rgba(212, 184, 150, 0.9); }

.example-vn {
  font-size: 14px;
  font-style: italic;
  color: #7A6040;
  margin: 3px 0;
}

.nightMode .example-vn { color: #7A7058; }

.example-ja {
  font-family: "UD Digi Kyokasho N-B", "Hiragino Kaku Gothic ProN", sans-serif;
  font-size: 14px;
  color: #5A3010;
}

.nightMode .example-ja {
  color: #A89878;
  font-family: "UD Digi Kyokasho N-R", "Hiragino Kaku Gothic ProN", sans-serif;
}

/* =========================================
   CLOZE / BOLD
   ========================================= */
.cloze {
  color: #6B2600;
  font-weight: bold;
}

.nightMode .cloze { color: #ff557f; }

b {
  color: #6B2600;
  font-family: Arial;
  font-weight: bold;
}

.nightMode b {
  color: #ff557f;
  font-weight: normal;
}

/* =========================================
   TYPE ANSWER FEEDBACK
   ========================================= */
#typeans {
  font-family: Arial, Helvetica, sans-serif;
  font-size: 28px !important;
  text-align: center !important;
}

#typeans span            { background-color: #F5EFE0; }
.nightMode #typeans span { background-color: #18160F; }

.typeBad               { color: #6B2600; font-family: Arial; font-size: 28px; }
.typeMissed, .typePass { color: #AA1010; font-family: Arial; font-size: 28px; }
.typeGood              { color: #AA1010; font-family: Arial; font-size: 28px; }

.nightMode .typeBad               { color: #FFDD3B; }
.nightMode .typeMissed,
.nightMode .typePass              { color: #ff557f; }
.nightMode .typeGood              { color: #ff557f; }

.typeKeyword {
  color: #6B2600;
  margin-top: -10px;
  margin-bottom: -6px;
}

.nightMode .typeKeyword { color: #ff557f; }
.mobile .typeKeyword    { color: #ff557f; margin-top: 3px; }

/* =========================================
   FULL VIETNAMESE
   ========================================= */
.full-vietnamese {
  border-radius: 8px;
  display: block;
  text-align: left;
  font-family: Arial, sans-serif;
  font-size: 14px;
  line-height: 1.7;
  margin-top: 10px;
  padding: 10px 14px;
  background: #EAE0C8;
  border: 0.5px solid #C9BAA0;
  opacity: 0.95;
}

.full-vietnamese img,
.full-vietnamese #pa_T_id          { display: none; }
.full-vietnamese b                 { color: #6B2600; }
.full-vietnamese i                 { color: #4A3A7A; font-style: normal; }
.full-vietnamese ul                { list-style: none; padding: 0; }
